advanced.CustomisedAppearance:
// JavaScript
import '@maersk-global/mds-components-core/mc-progress-indicator';

// CSS
mc-progress-indicator::part(wrapper) {
  min-width: 30px;
}

// HTML
<mc-progress-indicator
  value="50"
  max="100"
  variant="bar"
  label="Fetching data..."
  hiddenlabel
></mc-progress-indicator>

advanced.CustomColorThresholds:
// JavaScript
import '@maersk-global/mds-components-core/mc-progress-indicator';

// CSS
.custom-bar-color::part(progress) {
  background-color: red;
}
.custom-ring-color::part(progress) {
  stroke: red;
}

// HTML
<mc-progress-indicator
  value="50"
  max="100"
  variant="bar"
  label="50%"
  class="custom-bar-color"
  arialabel="Progress at 50 percent, custom bar color state"
></mc-progress-indicator>
<mc-progress-indicator
  value="50"
  max="100"
  variant="ring"
  label="50%"
  class="custom-ring-color"
  arialabel="Progress at 50 percent, custom ring color state"
></mc-progress-indicator>
